"""
DUR 노인주의 사유 텍스트 → 응급 위험 키워드 자동 매핑.

우선순위는 리스트 순서. 위쪽일수록 응급실에서 더 즉각적인 조치가 필요한 키워드.
"""

# (출력 키워드, [텍스트에서 찾을 패턴 리스트])
RISK_PATTERNS: list[tuple[str, list[str]]] = [
    ("출혈",     ["출혈", "지혈", "혈소판감소", "응고"]),
    ("저혈당",   ["저혈당"]),
    ("부정맥",   ["부정맥", "QT", "심실"]),
    ("호흡억제", ["호흡억제", "호흡곤란", "호흡정지"]),
    ("심혈관",   ["심혈관", "심부전", "심정지"]),
    ("저혈압",   ["혈압강하", "저혈압", "기립성"]),
    ("운동이상", ["추체외로", "이상운동", "근긴장", "지연성운동"]),
    ("낙상",     ["낙상", "어지럼", "어지러움", "어지러", "균형"]),
    ("졸음",     ["졸음", "진정", "수면제", "기면"]),
    ("인지",     ["기억", "인지", "섬망", "혼란", "치매"]),
    ("항콜린",   ["항콜린", "구갈", "변비", "요폐"]),
    ("간독성",   ["간독성", "간기능"]),
    ("신독성",   ["신독성", "신기능"]),
]


def extract_risk_keyword(reason_text: str) -> str:
    if not reason_text:
        return "노인주의"
    for keyword, patterns in RISK_PATTERNS:
        for p in patterns:
            if p in reason_text:
                return keyword
    return "노인주의"
